% 找到区域内最高点作为种子点
[maxVal, seedIdx] = max(img(:));
[seedRow, seedCol] = ind2sub(size(img), seedIdx);

% 定义阈值和生长条件
threshold = 50;
stopCondition = false;

% 初始化生长区域
region = false(size(img));

% 区域生长
while ~stopCondition
    % 标记当前生长的点
    region(seedRow, seedCol) = true;

    % 根据八邻域梯度方向生长
    [gx, gy] = imgradientxy(img);
    gradDir = atan2(gy(seedRow, seedCol), gx(seedRow, seedCol));

    % 获取八个相邻像素的坐标
    neighbors = [seedRow-1, seedCol-1; seedRow-1, seedCol; seedRow-1, seedCol+1; ...
                 seedRow, seedCol-1; seedRow, seedCol+1; ...
                 seedRow+1, seedCol-1; seedRow+1, seedCol; seedRow+1, seedCol+1];

    % 根据梯度方向选择下一个种子点
    [~, index] = max(gx(neighbors(:,1), neighbors(:,2)) * cos(gradDir) + gy(neighbors(:,1), neighbors(:,2)) * sin(gradDir));
    nextPoint = neighbors(index, :);

    % 更新种子点
    seedRow = nextPoint(1);
    seedCol = nextPoint(2);

    % 停止条件：超过边缘或像素值小于阈值
    if (seedRow < 1 || seedRow > size(img, 1) || seedCol < 1 || seedCol > size(img, 2) || img(seedRow, seedCol) < threshold)
        stopCondition = true;
    end
end

% 显示提取的区域
imshow(region);
```

