    weightedScore = zeros(1, 8);
    for i = 1:8
        if ~grownPoints(neighbors(i, 1), neighbors(i, 2))
            weightedScore(i) = gx(neighbors(i, 1), neighbors(i, 2)) * cos(gradDir) + gy(neighbors(i, 1), neighbors(i, 2)) * sin(gradDir);
        else
            weightedScore(i) = -Inf; % 设置已生长的点得分为负无穷，排除选择
        end
    end

    % 根据梯度方向选择下一个种子点
    [~, index] = max(weightedScore);
    nextPoint = neighbors(index, :);

    % 更新种子点
    seedRow = nextPoint(1);
    seedCol = nextPoint(2);

    % 停止条件：超过边缘或像素值小于阈值
    if (seedRow < 1 || seedRow > size(img, 1) || seedCol < 1 || seedCol > size(img, 2) || img(seedRow, seedCol) < threshold)
        stopCondition = true;
    end
end

% 显示提取的区域
imshow(region);
```

通过记录已经生长的像素，避免重复选择同一像素作为下一个种子点，可以有效避免陷入两个点之间梯度互相为最小的情况，从而最大程度避免死循环问题。希望这次修改能够解决你遇到的问题。如果还有其他疑问，请随时提出。
